INSERT INTO articles VALUES('art-001','Initial Dex Offering: Everything You Need to Know','initial-dex-offering','Learn what an IDO is, how it works, and why it''s becoming a popular way to launch tokens in the decentralized finance space.','Defi','./images/article-pic.jpg','Olopade Ipaye','./images/user-placeholder.svg','4 min read','2026-01-24','2026-01-24','2026-03-30 04:06:39',1,0,NULL,'[{"type":"heading","level":2,"text":"What Is an IDO?"},{"type":"paragraph","text":"An Initial DEX Offering (IDO) is a fundraising method where new cryptocurrency tokens are launched through a decentralized liquidity exchange. Unlike traditional ICOs (Initial Coin Offerings), IDOs allow projects to raise funds and list their tokens simultaneously on a decentralized exchange (DEX). This means that as soon as the sale is complete, the token is available for trading — no waiting period, no centralized gatekeepers."},{"type":"paragraph","text":"Think of it like a decentralized IPO. Instead of going through a bank or a centralized platform, the project uses smart contracts to handle everything — from collecting funds to distributing tokens."},{"type":"heading","level":2,"text":"How Do IDOs Work?"},{"type":"paragraph","text":"A project creates a token and partners with a launchpad platform (like DAO Maker, Polkastarter, or TrustSwap). The token is offered to the public through a smart contract on a DEX. Buyers send funds (usually stablecoins or the chain''s native token) to the smart contract. Tokens are distributed automatically. Liquidity is locked on the DEX."},{"type":"heading","level":3,"text":"Benefits of IDOs"},{"type":"paragraph","text":"One of the key benefits is Instant Liquidity. Because the token is listed on a DEX immediately after the sale, buyers can start trading right away. This removes the waiting period that often comes with centralized fundraising methods."}]',0);
INSERT INTO articles VALUES('art-002','Understanding Bitcoin Halving and Why It Matters','bitcoin-halving','Bitcoin halving is one of the most important events in crypto. Learn what happens, when it occurs, and how it affects the market.','Bitcoin','./images/article-pic.jpg','LoopBridge Team','./images/user-placeholder.svg','6 min read','2026-02-10','2026-02-10','2026-03-30 04:06:39',1,0,NULL,'[{"type":"heading","level":2,"text":"What Is Bitcoin Halving?"},{"type":"paragraph","text":"Bitcoin halving is a pre-programmed event that reduces the reward miners receive for validating transactions by 50%. It occurs approximately every four years (every 210,000 blocks) and is built into Bitcoin''s code to control inflation and limit the total supply to 21 million coins."}]',0);
INSERT INTO articles VALUES('art-003','How to Set Up and Secure Your First Crypto Wallet','secure-crypto-wallet','A step-by-step guide to setting up a crypto wallet, choosing between hot and cold storage, and protecting your private keys.','Security','./images/article-pic.jpg','LoopBridge Team','./images/user-placeholder.svg','5 min read','2026-02-18','2026-02-18','2026-03-30 04:06:39',1,0,NULL,'[{"type":"heading","level":2,"text":"Why You Need a Crypto Wallet"},{"type":"paragraph","text":"A crypto wallet is your gateway to the blockchain. It stores your private keys — the cryptographic passwords that prove ownership of your digital assets. Without a wallet, you can''t send, receive, or interact with any blockchain network."}]',0);
INSERT INTO articles VALUES('art-004','What Is DeFi and Why Should You Care?','what-is-defi','Decentralized Finance is reshaping how we think about money. Here''s a plain-English guide to DeFi, its tools, and its risks.','Defi','./images/article-pic.jpg','Olopade Ipaye','./images/user-placeholder.svg','7 min read','2026-03-01','2026-03-01','2026-03-30 04:06:39',0,0,NULL,'[{"type":"heading","level":2,"text":"DeFi in Plain English"},{"type":"paragraph","text":"DeFi stands for Decentralized Finance. It''s an umbrella term for financial services built on blockchain technology that operate without traditional intermediaries like banks, brokerages, or insurance companies."}]',0);
INSERT INTO articles VALUES('art-005','Airdrops Explained: Free Tokens or Hidden Traps?','airdrops-explained','Airdrops are a popular way to earn free tokens, but not all are safe. Learn how to spot legitimate airdrops and avoid scams.','Basics','./images/article-pic.jpg','LoopBridge Team','./images/user-placeholder.svg','5 min read','2026-03-05','2026-03-05','2026-03-30 04:06:39',0,0,NULL,'[{"type":"heading","level":2,"text":"What Is a Crypto Airdrop?"},{"type":"paragraph","text":"A crypto airdrop is when a blockchain project distributes free tokens to wallet addresses, usually as a marketing strategy, reward for early supporters, or to bootstrap a community."}]',0);
INSERT INTO articles VALUES('art-006','Understanding Stablecoins: Your Safe Haven in Crypto','understanding-stablecoins','Stablecoins bridge the gap between traditional finance and crypto. Learn how USDT, USDC, and DAI work — and when to use them.','Stablecoin','./images/article-pic.jpg','LoopBridge Team','./images/user-placeholder.svg','4 min read','2026-03-12','2026-03-12','2026-03-30 04:06:39',0,0,NULL,'[{"type":"heading","level":2,"text":"What Are Stablecoins?"},{"type":"paragraph","text":"Stablecoins are cryptocurrencies designed to maintain a stable value by being pegged to a reserve asset, usually a fiat currency like the US dollar. They combine the benefits of blockchain technology — speed, transparency, borderless transfers — with the price stability of traditional money."}]',0);
