INSERT INTO courses VALUES('course-001','Web3 & Metaverse Fundamentals','web3-metaverse-fundamentals','Build a strong foundation in Web3, crypto, and security essentials.',NULL,'Adeoluwa Boboye','./images/user-placeholder.svg','8 hours','Beginner','beginner',0.0,'2026-01-15','2026-03-30T04:06:39.956Z','2026-03-30 04:06:39',1,0,NULL,'[{"title":"Blockchain Fundamentals","subsections":[{"title":"Introduction to blockchain technology","type":"video","duration":"5 min"},{"title":"How blocks are linked and validated","type":"video","duration":"5 min"},{"title":"Public vs private blockchains","type":"video","duration":"5 min"},{"title":"Quiz: Blockchain Basics","type":"quiz","duration":"3 min"}]},{"title":"Crypto Fundamentals","subsections":[{"title":"What is cryptocurrency?","type":"video","duration":"5 min"},{"title":"How wallets and keys work","type":"video","duration":"5 min"},{"title":"Understanding gas fees","type":"video","duration":"5 min"},{"title":"Quiz: Crypto Fundamentals","type":"quiz","duration":"3 min"}]},{"title":"Web3 & Metaverse","subsections":[{"title":"What is Web3?","type":"video","duration":"5 min"},{"title":"Decentralized applications (dApps)","type":"video","duration":"5 min"},{"title":"The Metaverse explained","type":"video","duration":"5 min"},{"title":"Quiz: Web3 & Metaverse","type":"quiz","duration":"3 min"}]}]','This course introduces you to the core concepts behind Web3, blockchain, and the metaverse. You''ll learn how blockchain technology works, what makes crypto different from traditional money, and how decentralized applications are changing the internet.','["Understand the fundamentals of blockchain technology and how it works","Navigate the crypto landscape including wallets, tokens, and gas fees","Grasp the essentials of DeFi, Web3, and the evolving metaverse"]');
INSERT INTO courses VALUES('course-002','Setting Up and Securing Your Wallet','wallet-security','Learn to create, manage, and protect your cryptocurrency wallets.',NULL,'LoopBridge Team','./images/user-placeholder.svg','4 hours','Beginner','beginner',0.0,'2026-01-20','2026-03-30T04:06:39.956Z','2026-03-30 04:06:39',1,0,NULL,'[{"title":"Wallet Types","subsections":[{"title":"Hot wallets vs cold wallets","type":"video","duration":"6 min"},{"title":"Setting up MetaMask","type":"video","duration":"8 min"},{"title":"Quiz: Wallet Types","type":"quiz","duration":"3 min"}]},{"title":"Security Best Practices","subsections":[{"title":"Protecting your seed phrase","type":"video","duration":"5 min"},{"title":"Recognizing phishing attacks","type":"video","duration":"5 min"},{"title":"Quiz: Security","type":"quiz","duration":"3 min"}]}]','Your crypto wallet is the most important tool in Web3. This course teaches you how to choose the right wallet, set it up securely, and protect your assets from common threats.','["Choose between hot and cold wallets based on your needs","Set up and configure a MetaMask wallet","Implement security best practices to protect your private keys"]');
INSERT INTO courses VALUES('course-003','Naira-to-Crypto Trading Basics','naira-crypto-trading','Understand how to buy and sell crypto using Nigerian Naira on peer-to-peer platforms.',NULL,'LoopBridge Team','./images/user-placeholder.svg','5 hours','Beginner','beginner',0.0,'2026-02-01','2026-03-30T04:06:39.956Z','2026-03-30 04:06:39',1,0,NULL,'[]','Learn the fundamentals of buying and selling crypto with Naira through WhatsApp-based OTC platforms and P2P exchanges.','["Understand how P2P trading works","Navigate exchange rates and fees","Use LoopBridge''s WhatsApp exchange safely"]');
INSERT INTO courses VALUES('course-004','How to Read a Candlestick Chart','candlestick-charts','Learn to read and interpret candlestick charts for smarter trading decisions.',NULL,'Adeoluwa Boboye','./images/user-placeholder.svg','6 hours','Intermediate','intermediate',45.0,'2026-02-15','2026-03-30T04:06:39.956Z','2026-03-30 04:06:39',1,0,NULL,'[]','Candlestick charts are the language of trading. This course teaches you to read price action, identify patterns, and make informed decisions based on chart data.','["Read and interpret candlestick patterns","Identify support and resistance levels","Combine chart analysis with trading strategy"]');
INSERT INTO courses VALUES('course-005','Spot vs Futures Trading','spot-vs-futures','Understand the key differences between spot and futures trading and when to use each.',NULL,'LoopBridge Team','./images/user-placeholder.svg','5 hours','Intermediate','intermediate',20.0,'2026-02-20','2026-03-30T04:06:39.956Z','2026-03-30 04:06:39',1,0,NULL,'[]','This course breaks down the differences between buying crypto on the spot market versus trading futures contracts, including leverage, margin, and risk management.','["Differentiate between spot and futures markets","Understand leverage and margin requirements","Apply risk management techniques to each trading style"]');
INSERT INTO courses VALUES('course-006','Identifying Promising Projects Early','early-project-identification','Explore deeper participation, analysis, and onchain opportunities in the Web3 ecosystem.',NULL,'Olopade Ipaye','./images/user-placeholder.svg','10 hours','Advanced','advanced',60.0,'2026-03-01','2026-03-30T04:06:39.957Z','2026-03-30 04:06:39',1,0,NULL,'[]','Learn the frameworks and tools experienced crypto analysts use to evaluate early-stage projects, assess tokenomics, and identify investment opportunities before the crowd.','["Evaluate project fundamentals: team, tokenomics, roadmap","Use on-chain data to spot emerging trends","Assess risk-reward for early-stage investments"]');
