

CREATE TABLE users (
            id            TEXT PRIMARY KEY,
            username      TEXT UNIQUE NOT NULL,
            password_hash TEXT NOT NULL,
            display_name  TEXT NOT NULL DEFAULT '',
            email         TEXT UNIQUE NOT NULL,
            role          TEXT NOT NULL DEFAULT 'user' CHECK(role IN ('admin','author','user')),
            avatar        TEXT,
            author_of     TEXT DEFAULT '[]',
            created_at    TEXT NOT NULL DEFAULT (NOW()),
            updated_at    TEXT NOT NULL DEFAULT (NOW())
        , google_id TEXT, phone TEXT, phone_verified INTEGER NOT NULL DEFAULT 0);
CREATE TABLE sessions (
            id         TEXT PRIMARY KEY,
            user_id    TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
            created_at TEXT NOT NULL DEFAULT (NOW()),
            expires_at TEXT NOT NULL
        );
CREATE TABLE articles (
            id           TEXT PRIMARY KEY,
            title        TEXT NOT NULL,
            slug         TEXT,
            description  TEXT,
            category     TEXT,
            image        TEXT,
            author_name  TEXT,
            author_avatar TEXT,
            read_time    TEXT,
            published_at TEXT,
            updated_at   TEXT NOT NULL DEFAULT (NOW()),
            created_at   TEXT NOT NULL DEFAULT (NOW()),
            featured     INTEGER NOT NULL DEFAULT 0,
            deleted      INTEGER NOT NULL DEFAULT 0,
            deleted_at   TEXT,
            content      TEXT DEFAULT '[]',
            views        INTEGER NOT NULL DEFAULT 0
        );
CREATE TABLE courses (
            id           TEXT PRIMARY KEY,
            title        TEXT NOT NULL,
            slug         TEXT,
            description  TEXT,
            image        TEXT,
            author_name  TEXT,
            author_avatar TEXT,
            duration     TEXT,
            level        TEXT,
            track        TEXT,
            price        REAL NOT NULL DEFAULT 0,
            published_at TEXT,
            updated_at   TEXT NOT NULL DEFAULT (NOW()),
            created_at   TEXT NOT NULL DEFAULT (NOW()),
            approved     INTEGER NOT NULL DEFAULT 1,
            deleted      INTEGER NOT NULL DEFAULT 0,
            deleted_at   TEXT,
            topics       TEXT DEFAULT '[]',
            overview     TEXT,
            learning_objectives TEXT DEFAULT '[]'
        );
CREATE TABLE faqs (
            id       TEXT PRIMARY KEY,
            category TEXT NOT NULL,
            question TEXT NOT NULL,
            answer   TEXT NOT NULL,
            sort_order INTEGER NOT NULL DEFAULT 0
        );
CREATE TABLE progress (
            user_id          TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
            course_id        TEXT NOT NULL REFERENCES courses(id) ON DELETE CASCADE,
            enrolled_at      TEXT NOT NULL DEFAULT (NOW()),
            last_accessed_at TEXT NOT NULL DEFAULT (NOW()),
            completed_subs   TEXT DEFAULT '[]',
            PRIMARY KEY (user_id, course_id)
        );
CREATE TABLE uploads (
            id          TEXT PRIMARY KEY,
            filename    TEXT NOT NULL,
            original_name TEXT NOT NULL,
            mime_type   TEXT NOT NULL,
            size        INTEGER NOT NULL DEFAULT 0,
            path        TEXT NOT NULL,
            url         TEXT NOT NULL,
            uploaded_by TEXT REFERENCES users(id) ON DELETE SET NULL,
            created_at  TEXT NOT NULL DEFAULT (NOW())
        );
CREATE TABLE analytics_events (
            id           SERIAL PRIMARY KEY,
            session_id   TEXT NOT NULL,
            user_id      TEXT,
            event_type   TEXT NOT NULL,
            page         TEXT,
            target       TEXT,
            course_id    TEXT,
            article_id   TEXT,
            quiz_id      TEXT,
            score        REAL,
            duration_ms  INTEGER,
            metadata     TEXT DEFAULT '{}',
            ip           TEXT,
            user_agent   TEXT,
            referrer     TEXT,
            created_at   TEXT NOT NULL DEFAULT (NOW())
        );
CREATE TABLE otp_codes (
            id         SERIAL PRIMARY KEY,
            phone      TEXT NOT NULL,
            code       TEXT NOT NULL,
            channel    TEXT NOT NULL DEFAULT 'email',
            expires_at TEXT NOT NULL,
            used       INTEGER NOT NULL DEFAULT 0,
            created_at TEXT NOT NULL DEFAULT (NOW())
        );
CREATE TABLE subscribers (
            id            SERIAL PRIMARY KEY,
            email         TEXT UNIQUE NOT NULL,
            source        TEXT DEFAULT 'newsletter',
            active        INTEGER NOT NULL DEFAULT 1,
            subscribed_at TEXT NOT NULL DEFAULT (NOW()),
            unsubscribed_at TEXT
        );
CREATE INDEX idx_analytics_user    ON analytics_events(user_id);
CREATE INDEX idx_analytics_session ON analytics_events(session_id);
CREATE INDEX idx_analytics_type    ON analytics_events(event_type);
CREATE INDEX idx_analytics_page    ON analytics_events(page);
CREATE INDEX idx_analytics_date    ON analytics_events(created_at);
CREATE INDEX idx_otp_phone ON otp_codes(phone);
CREATE INDEX idx_subscribers_email ON subscribers(email);

